-- Replace generic section templates with 27 business-specific sections from spreadsheet.
-- Adds practice_prompts JSONB column for practice-specific LLM validation prompts.
--
-- WARNING: This deletes all existing global section templates and their referencing brief_sections.
-- Existing practice_templates may have stale section IDs.

-- 1. Add practice_prompts column
ALTER TABLE section_templates ADD COLUMN IF NOT EXISTS practice_prompts jsonb;

-- 2. Remove brief_sections referencing old global templates
DELETE FROM brief_sections
  WHERE section_template_id IN (
    SELECT id FROM section_templates WHERE organisation_id IS NULL
  );

-- 3. Delete old global section templates
DELETE FROM section_templates WHERE organisation_id IS NULL;

