INSERT INTO section_templates (id, organisation_id, name, description, category, ai_evaluation_criteria, practice_prompts)
VALUES
  ('practice-specialties', NULL, 'Practice Specialties', 'What does this practice area produce? Used to match briefs to the right team.', 'Triage', NULL, '{"Creative": "CREATIVE — OUTPUTS:\n• Campaign concepts and big ideas\n• TVC / digital film production\n• Photography (stills, campaign shoots)\n• Campaign copywriting\n• Integrated campaign creative across channels\n• Social media creative assets\n• OOH / print advertising\n• Radio / audio creative\n• Brand campaign platforms", "Design": "DESIGN — OUTPUTS:\n• Brand visual identity systems\n• Logo design and refinement\n• Packaging design (structural and graphic)\n• Brand books and style guides\n• Design toolkits and templates\n• Environmental / signage design\n• Publication and report design\n• Digital design systems (UI kits, component libraries)", "Corporate Comms": "CORPORATE COMMS — OUTPUTS:\n• Corporate communications strategy\n• Issues and crisis management plans\n• Corporate narrative and messaging frameworks\n• Executive profiling and thought leadership programs\n• Internal communications (staff updates, town halls, intranet)\n• Spokesperson training and media preparation\n• Investor, government, and regulator communications\n• ESG, sustainability, and social licence storytelling\n• Stakeholder engagement strategies", "Consumer PR": "CONSUMER PR — OUTPUTS:\n• Media relations campaigns and media pitching\n• Earned media strategy and placement\n• Thought leadership programs\n• Influencer identification, strategy, and management\n• Event activation and media event coordination\n• Press kits, media materials, and pitch angles\n• Content strategy and content engine playbooks\n• Spokesperson identification and briefing\n• Media monitoring and reporting\n• Influencer and media gifting programs", "Activations": "ACTIVATIONS — OUTPUTS:\n• Event concept development and creative direction\n• Brand experience and activation design\n• Pop-up installations and immersive environments\n• Experiential marketing campaigns\n• Product launch events and reveal moments\n• Festival, sponsorship, and partnership activations\n• Sampling and trial programs\n• Branded merchandise and promotional items\n• Props, set builds, and custom fabrication\n• Event production and logistics management\n• Roadshow and touring activation programs\n• Trade show and conference activations"}'),
  ('practice-criteria', NULL, 'Practice Criteria', 'Score the brief 1-10 for how applicable it is to this practice area. Used to route briefs.', 'Triage', NULL, '{"Creative": "TRIAGE — Score this brief out of 10 for CREATIVE applicability.\n\nScore 1 point for each signal present in the brief:\n1. The brief requires a new campaign concept or big idea\n2. The brief mentions standing out, brand fatigue, or need for distinction in a crowded category\n3. There is a new product or service launch requiring high-impact creative visibility\n4. Objectives focus on emotional connection — brand love, affinity, or changing consumer perception\n5. The brief requires production of film, photography, TVC, or hero content\n6. Success metrics include Brand Awareness, Ad Recall, or Brand Lift\n7. The brief is for a consumer-facing audience (not purely corporate/stakeholder)\n8. The work spans multiple channels requiring integrated creative thinking\n9. The brief includes or implies a need for campaign copywriting\n10. The work should feel evolutionary or is a creative step-change for the brand\n\nReturn a score out of 10 and a one-sentence rationale.\nA score of 7+ = strong fit. 4-6 = possible fit, may need combined teams. 1-3 = unlikely fit.", "Design": "TRIAGE — Score this brief out of 10 for DESIGN applicability.\n\nScore 1 point for each signal present in the brief:\n1. The brief requires a new or refreshed brand visual identity\n2. The brief involves packaging design (structural or graphic)\n3. The brief asks for a logo, wordmark, or brand mark\n4. The brief requires a brand book, style guide, or design toolkit\n5. The work is primarily about visual/structural brand assets, not campaign ideas\n6. Technical specifications are mentioned (print specs, die-lines, colour profiles, file formats)\n7. The brief references design systems, templates, or modular visual assets\n8. The work involves environmental, signage, or spatial design\n9. The brief focuses on how the brand looks and feels rather than what it says\n10. The brief is about design refinement or brand consistency rather than a campaign\n\nReturn a score out of 10 and a one-sentence rationale.\nA score of 7+ = strong fit. 4-6 = possible fit, may need combined teams. 1-3 = unlikely fit.", "Corporate Comms": "TRIAGE — Score this brief out of 10 for CORPORATE COMMS applicability.\n\nScore 1 point for each signal present in the brief:\n1. Social listening shows a spike in complaints, backlash, or negative sentiment\n2. There has been an operational failure — product recall, data breach, or service outage\n3. Internal misalignment — need to communicate complex changes (layoffs, restructuring) to staff\n4. Primary audience is stakeholders (investors, government, regulators, board) rather than consumers\n5. The brief requires corporate narrative, reputation management, or ESG positioning\n6. Success metrics include Sentiment Stabilisation, Employee eNPS, or Share Price Stability\n7. The brief involves executive profiling, spokesperson training, or leadership comms\n8. The work requires internal communications strategy or delivery\n9. The brief involves government, regulatory, or investor engagement\n10. The issue is serious but managed — not an immediate crisis requiring urgent response\n\nReturn a score out of 10 and a one-sentence rationale.\nA score of 7+ = strong fit. 4-6 = possible fit, may need combined teams. 1-3 = unlikely fit.\nNOTE: If the situation is an active/imminent crisis requiring response within 24-48 hours, score Crisis Comms instead.", "Consumer PR": "TRIAGE — Score this brief out of 10 for CONSUMER PR applicability.\n\nScore 1 point for each signal present in the brief:\n1. The client needs third-party credibility through earned media, not just paid advertising\n2. There is a newsworthy announcement — merger, acquisition, CSR initiative, major hire, product launch\n3. The brief aims to reach audiences through journalists, editors, or media gatekeepers\n4. Influencer identification, engagement, or management is required\n5. Success metrics include Earned Impressions, Media Placements, or Sentiment Analysis\n6. The brief requires thought leadership or expert positioning\n7. Event activation or media event coordination is needed\n8. The work involves media relations, pitching, or press material development\n9. The brief references building or managing brand reputation through public storytelling\n10. The client needs media monitoring, reporting, or ongoing media retainer services\n\nReturn a score out of 10 and a one-sentence rationale.\nA score of 7+ = strong fit. 4-6 = possible fit, may need combined teams. 1-3 = unlikely fit.", "Activations": "TRIAGE — Score this brief out of 10 for ACTIVATIONS applicability.\n\nScore 1 point for each signal present in the brief:\n1. The brief requires a physical or experiential brand moment (event, pop-up, installation, sampling)\n2. There is a product launch, reveal, or unveiling that requires a live or in-person element\n3. The brief mentions consumer engagement through physical touchpoints, not just digital or media\n4. A sponsorship, festival, or partnership needs to be activated with a branded presence\n5. The brief requires branded merchandise, promotional items, props, or custom-built elements\n6. Success metrics include attendance, footfall, dwell time, samples distributed, or social sharing from events\n7. The brief references immersive, experiential, or interactive brand experiences\n8. There is a need for roadshow, touring, or multi-location activation\n9. The brief requires event production, logistics, or venue management\n10. The work involves trade, conference, or B2B event activation\n\nReturn a score out of 10 and a one-sentence rationale.\nA score of 7+ = strong fit. 4-6 = possible fit, may need combined teams. 1-3 = unlikely fit."}'),
  ('background-context', NULL, 'Background / Context', 'What''s happened/happening that has led to this brief?', 'Job to be done', NULL, '{"Creative": "CREATIVE — Background / Context requirements:\n\nThis section needs to include:\n• A clear explanation of what is happening in the business, brand, or product that has led to this brief\n• Any relevant cultural, competitor, or regulatory context that is important to know\n• A snapshot of how the brand typically shows up visually and verbally — category norms and existing brand behaviour\n• Whether this work should feel evolutionary (building on what exists) or a creative step-change (new direction)\n• Any relevant market or competitive factors that could shape the creative approach\n• Enough context that a creative team member with no prior knowledge of the brand could understand the situation", "Design": "DESIGN — Background / Context requirements:\n\nThis section needs to include:\n• What is happening in the business, brand, or product that has led to this design brief\n• Any cultural, competitor, or regulatory context relevant to the design challenge\n• Reference to existing brand visual language, design systems, or brand identity\n• Whether this is an evolution of existing design or a new visual direction\n• Enough context for a designer unfamiliar with the brand to understand the starting point", "Corporate Comms": "CORPORATE COMMS — Background / Context requirements:\n\nThis section needs to include:\n• Who is briefing us — background to the client, company, brand (short synopsis of who they are)\n• Why they have reached out — the problem or opportunity they want help with (e.g. protect reputation, manage risk, issues, stakeholder trust, corporate narrative and positioning)\n• Links to or inclusion of any relevant data, research, or consumer/stakeholder sentiment\n• Enough context for a corporate comms strategist to understand the corporate landscape and communications challenge", "Consumer PR": "CONSUMER PR — Background / Context requirements:\n\nThis section needs to include:\n• Who is briefing us — background to the client, company, brand (short synopsis of who they are)\n• Why they have reached out — the problem or opportunity (e.g. new product launch, brand positioning update, community initiative, influencer campaign opportunity)\n• Links to or inclusion of any relevant data, research, or consumer sentiment\n• Enough context for a PR strategist to understand the media landscape around this brand", "Activations": "ACTIVATIONS — Background / Context requirements:\n\nThis section needs to include:\n• What is happening in the business, brand, or product that has led to this brief\n• Any relevant context around the event or activation opportunity (e.g. sponsorship commitment, trade calendar, product launch, seasonal moment)\n• Previous activations or events the brand has run — what worked, what didn''t, and what the benchmark is\n• Cultural, competitive, or market context that should influence the activation approach\n• Whether this is a one-off event or part of a recurring or touring program\n• Does this tie in with any other activity you have planned?"}'),
  ('problem-or-opportunity', NULL, 'Problem or Opportunity', 'What weaknesses are we solving for or strengths can we leverage?', 'Job to be done', NULL, '{"Creative": "CREATIVE — Problem or Opportunity requirements:\n\nThis section needs to include:\n• A specific problem or opportunity stated in concrete terms (not just background repeated)\n• The core creative challenge or tension — an insight or gap that strong creative thinking could unlock\n• Why this problem is worth solving creatively — what makes it interesting and briefable\n• What happens if this is not addressed (the stakes)\n• Clear distinction from the Background section — this should add a strategic lens, not more context", "Design": "DESIGN — Problem or Opportunity requirements:\n\nThis section needs to include:\n• What the design specifically needs to address — the design challenge characterised clearly\n• The current visual or design gap articulated\n• What success looks like from a design perspective\n• Clear distinction from Background — this is the specific design problem, not general context", "Corporate Comms": "CORPORATE COMMS — Problem or Opportunity requirements:\n\nThis section needs to include:\n• The specifics of the problems or opportunities relevant to answering the brief — what is at the heart of the job to do\n• Relevant factors such as: business/reputational issue, negative sentiment, industry issue, government engagement requirement, lack of awareness, competitor issues, inconsistent tone of voice, media portrayal, category leadership opportunity, new audience segments\n• The business and reputational stakes clearly stated\n• Clear distinction from Background — this drills into the core corporate comms challenge", "Consumer PR": "CONSUMER PR — Problem or Opportunity requirements:\n\nThis section needs to include:\n• The specifics of the problems or opportunities that PR activity can address\n• Relevant factors such as: lack of category awareness, audiences favouring a competitor, inconsistent tone of voice, media portrayal issues, category leadership opportunity, new audience segments\n• The shift needed in public perception or media coverage\n• Clear distinction from Background — this focuses on the PR-addressable challenge", "Activations": "ACTIVATIONS — Problem or Opportunity requirements:\n\nThis section needs to include:\n• The specific challenge or opportunity that a physical activation can address (e.g. low brand awareness, need for tangible product experience, sponsorship asset underperforming, competitor owning physical presence in category, earned media coverage, influencer engagement)\n• Why a live, experiential, or physical activation is the preferred approach over other channels\n• The experience gap — what the audience currently experiences and the reasons for this vs what the brand wants them to experience\n• Any insight into audience behaviour in physical environments (e.g. dwell patterns, event attendance habits, sampling receptiveness)"}'),
  ('the-task', NULL, 'The Task', 'What do we need to do?', 'Job to be done', NULL, '{"Creative": "CREATIVE — The Task requirements:\n\nThis section needs to include:\n• The type of campaign clearly identified (e.g. brand campaign, retail campaign, product campaign, behaviour change, sponsorship integration)\n• Whether single product or multi-product/range if applicable\n• Whether this is a new concept or work under an existing campaign platform\n• The type of creative thinking required — strategic (new platform) vs executional (adaptation)\n• Enough specificity for the team to understand what kind of work they are being asked to produce and to scope resources", "Design": "DESIGN — The Task requirements:\n\nThis section needs to include:\n• The type of design work clearly identified (e.g. pack design, logo, brand visual identity, brand book)\n• Whether this is new creation or refinement of existing design\n• Enough specificity for a design team to understand scope and nature of the work\n• Clear scope boundaries — what is included and what is not", "Corporate Comms": "CORPORATE COMMS — The Task requirements:\n\nThis section needs to include:\n• The corporate communications task clearly defined (e.g. crisis plan, corporate narrative, stakeholder engagement strategy, executive profiling, internal comms, media relations)\n• Whether this is strategy, execution, or ongoing retainer\n• Relationship to other workstreams if applicable\n• Enough specificity for a comms strategist to scope the work", "Consumer PR": "CONSUMER PR — The Task requirements:\n\nThis section needs to include:\n• The PR task clearly defined (e.g. product launch campaign, ongoing media retainer, influencer campaign, event activation, brand storytelling, thought leadership)\n• Type of program — campaign vs retainer vs project\n• Distinction between strategy and execution\n• Enough specificity for a PR team to scope and plan", "Activations": "ACTIVATIONS — The Task requirements:\n\nThis section needs to include:\n• The type of activation clearly identified (e.g. product launch event, pop-up experience, sampling program, sponsorship activation, trade stand, brand installation, roadshow, conference presence)\n• Scale and scope — single event vs multi-location, one-off vs recurring\n• Whether the team is responsible for concept development, production, logistics, or all three\n• The level of creative freedom vs prescribed brief (e.g. activating within an existing campaign platform vs creating a standalone experience)"}'),
  ('product-brand', NULL, 'Product / Brand', 'What is the focus? Key information?', 'Job to be done', NULL, '{"Creative": "CREATIVE — Product / Brand requirements:\n\nThis section needs to include:\n• The key brand or product features, attributes, and differentiators relevant to messaging\n• Watch-outs on messaging — what is legally claimable vs what is not\n• Competitive positioning context\n• What makes the product/brand creatively interesting — emotional hooks or cultural relevance\n• Clear separation of constraints from opportunities\n• Enough detail for a creative team unfamiliar with the product to develop messaging", "Design": "DESIGN — Product / Brand requirements:\n\nThis section needs to include:\n• The product or brand clearly identified with visual references and existing assets\n• Product form factors, materials, or technical specifications relevant to design\n• Existing brand assets or visual language referenced\n• Enough information for a designer to understand what they are designing for", "Corporate Comms": "CORPORATE COMMS — Product / Brand requirements:\n\nThis section needs to include:\n• The company, brand, or product at the centre of this brief\n• Key corporate messaging pillars and value propositions\n• Any sensitivities around how the brand/company should be positioned in corporate communications\n• Enough information for on-brand corporate messaging", "Consumer PR": "CONSUMER PR — Product / Brand requirements:\n\nThis section needs to include:\n• The product or brand at the centre of this brief with consumer-facing messaging\n• Unique selling propositions and proof points suitable for media outreach\n• Claims or evidence that can be used in pitching\n• Key story angles that make this product/brand newsworthy", "Activations": "ACTIVATIONS — Product / Brand requirements:\n\nThis section needs to include:\n• The product, brand, or service being activated — what needs to be physically experienced, sampled, or demonstrated\n• Key product features or attributes that should come to life in the activation (e.g. taste, texture, performance, technology, craft)\n• Any product handling, storage, or safety requirements (e.g. temperature-controlled sampling, age-restricted products, health and safety compliance)\n• Brand look and feel requirements for physical environments — existing visual identity, materials, finishes, brand colours in physical form"}'),
  ('target-audience', NULL, 'Target Audience', 'Profile and any relevant insight', 'Job to be done', NULL, '{"Creative": "CREATIVE — Target Audience requirements:\n\nThis section needs to include:\n• The creative target audience AND the media buy target defined — and whether they are the same (if not, the reasoning)\n• Demographic data (age, gender, location, life stage, income)\n• Attitudinal and behavioural data — mindset, motivations, emotional drivers, cultural context\n• What the audience cares about, what they are sceptical of, and what creative or visual language resonates\n• Any target audience research, learning, or presentations attached or referenced\n• The audience described as people, not segments — human and specific enough to write to/for", "Design": "DESIGN — Target Audience requirements:\n\nThis section needs to include:\n• The creative target audience identified\n• Demographic and profiling data relevant to the design task\n• Attitudinal or behavioural data that informs design choices (visual preferences, accessibility needs, usage context)\n• Enough context to guide aesthetic and functional design decisions", "Corporate Comms": "CORPORATE COMMS — Target Audience requirements:\n\nThis section needs to include:\n• Who the brand/company wants to communicate with — mapped using inform, consult, and engage framework\n• Current vs prospective audiences, stakeholders, and media distinguished\n• Any demographic details relevant to corporate communications\n• The communication needs and preferences of each stakeholder group", "Consumer PR": "CONSUMER PR — Target Audience requirements:\n\nThis section needs to include:\n• Who the brand/company wants to communicate with — who is informed, consulted, and engaged\n• Current vs prospective audiences distinguished\n• Demographic details relevant to media targeting and influencer identification\n• Enough detail for targeted media and influencer outreach", "Activations": "ACTIVATIONS — Target Audience requirements:\n\nThis section needs to include:\n• Who the activation is designed to reach — primary and secondary audiences\n• Demographic and behavioural profile relevant to physical experiences (e.g. commuters, festival-goers, parents with children, trade professionals)\n• How the audience behaves in the activation environment (e.g. time-poor vs browsing, receptive to sampling, likely to share on social)\n• Desired audience volume and flow (e.g. high footfall public event vs curated invite-only media and influencer event)"}'),
  ('key-objectives', NULL, 'Key Objective(s)', 'Business, marketing, comms as appropriate', 'Job to be done', NULL, '{"Creative": "CREATIVE — Key Objectives requirements:\n\nThis section needs to include:\n• Each objective clearly stated as an outcome (not an activity)\n• Objectives layered by type — business, brand, marketing, and comms as appropriate\n• Specific metric values and the delta vs current state (e.g. what % uplift is required) where known\n• How the audience should think, feel, or behave differently as a result of the work\n• 2-3 focused objectives rather than an unfocused list", "Design": "DESIGN — Key Objectives requirements:\n\nThis section needs to include:\n• A clear design objective that goes beyond ''make it look good''\n• What the design needs to achieve functionally and emotionally\n• Measurable indicators where possible (e.g. shelf standout, brand recognition, usability)\n• Alignment with the design task described in the brief", "Corporate Comms": "CORPORATE COMMS — Key Objectives requirements:\n\nThis section needs to include:\n• Objectives specific to corporate communications outcomes\n• Relevant examples addressed: brand awareness, market/brand positioning, stakeholder engagement, ROI metrics, media/consumer sentiment, media exposure, website traffic, engagement\n• What success looks like per key deliverable (e.g. media strategy success, sentiment shift, reputation score, stakeholder engagement)\n• Measurable indicators for each objective", "Consumer PR": "CONSUMER PR — Key Objectives requirements:\n\nThis section needs to include:\n• PR-specific objectives with measurable targets\n• Relevant examples: brand awareness, market positioning, successful product launch, ambassador identification, influencer impact, event attendance, ROI metrics, media/consumer sentiment, media exposure, website traffic, engagement\n• Success defined in terms of media outcomes, consumer engagement, and brand metrics", "Activations": "ACTIVATIONS — Key Objectives requirements:\n\nThis section needs to include:\n• Activation-specific objectives stated as outcomes (e.g. drive product trial, launch a new product/offering with impact, create awareness, generate social content, build brand affinity through experience, capture data/leads, demonstrate product capability, foot traffic, earned PR)\n• Measurable targets: attendance, samples distributed, dwell time, social shares/UGC generated, leads captured, NPS or satisfaction scores, sales conversion, media/influencer attendance, earned coverage\n• Whether the activation serves brand-building, conversion, data capture, or a combination\n• How the activation ladders up to broader campaign or business objectives"}'),
  ('key-deliverables', NULL, 'Key Deliverable(s)', 'What output is required?', 'Job to be done', NULL, '{"Creative": "CREATIVE — Key Deliverables requirements:\n\nThis section needs to include:\n• Specific deliverables listed with format and quantity (e.g. ''a 30\" piece of film'', ''30 social assets'')\n• Whether this is a new idea or work under an existing campaign platform\n• Any known mandatory deliverables and channel-specific requirements\n• What is NOT a deliverable — exclusions stated to manage scope creep\n• Enough specificity for a producer to create a production schedule", "Design": "DESIGN — Key Deliverables requirements:\n\nThis section needs to include:\n• Design deliverables specified with quantities (number of options, development rounds, final deliverables)\n• Relevant technical details (file formats, dimensions, colour profiles, print specs)\n• The design process outlined (concepts > revisions > finals)\n• Clear distinction between exploration phase and final delivery", "Corporate Comms": "CORPORATE COMMS — Key Deliverables requirements:\n\nThis section needs to include:\n• Specific corporate comms deliverables listed: communications strategy, issues/crisis management, corporate messaging/narrative, media strategy, CEO/executive/board comms, executive profiling, investor/government/regulator comms, ESG/sustainability storytelling, internal comms alignment\n• Scope of each deliverable clear enough to resource and timeline\n• Priority or phasing indicated if multiple deliverables", "Consumer PR": "CONSUMER PR — Key Deliverables requirements:\n\nThis section needs to include:\n• PR deliverables specifically listed: campaign ideation, spokesperson ID, media targets, media materials, pitch volumes, influencer family, content strategy, comms strategy, content engine playbook, PR implementation plan, media event coordination, guest list management, media channel planning, media list, pitch angles, thought leadership, event activation, influencer strategy, media/influencer gifting\n• Success metrics per deliverable (e.g. ''X tier-1 coverage with message pull-through'', ''X creators with Y engagement quality'')\n• Quantities and frequencies indicated where applicable", "Activations": "ACTIVATIONS — Key Deliverables requirements:\n\nThis section needs to include:\n• Specific deliverables listed: event concept, event amplification via earned, owned and paid channels, design assets, build elements\n• Any merchandise or branded props required (type, quantity, specifications) and who will supply — the client or the agency needs to get these made by a supplier\n• Technical requirements: lighting, power, connectivity, POS systems, data capture technology\n• Design requirements: collateral, signage, digital, physical assets for the activation space, merchandise\n• Digital requirements: app, giveaway entry mechanism, landing page\n• Content capture requirements (photography, videography, live social content creation on-site)\n• PR requirements: are we pitching this to media or engaging with media\n• Post-event deliverables: reporting, data handover, debrief documentation, store physical assets or send to client"}'),
  ('key-considerations', NULL, 'Key Considerations', 'What do we need to take into account / be mindful of?', 'Job to be done', NULL, '{"Creative": "CREATIVE — Key Considerations requirements:\n\nThis section needs to include:\n• Key brand or product features/attributes to consider in messaging strategy\n• Watch-outs on messaging — legal claimability, sensitivities\n• Tonality guardrails (e.g. ''playful but professional'')\n• Seasonal timing constraints and brand voice guidelines\n• Sensitivities regarding current news cycles or competitor activity\n• ''Third rails'' — topics or angles the brand absolutely refuses to touch\n• Balance of what to do AND what to avoid", "Design": "DESIGN — Key Considerations requirements:\n\nThis section needs to include:\n• Brand guidelines that must be followed\n• Accessibility requirements\n• Production constraints or printing specifications\n• Platform-specific requirements\n• Both aesthetic and technical guardrails", "Corporate Comms": "CORPORATE COMMS — Key Considerations requirements:\n\nThis section needs to include:\n• Other agencies/teams working on related projects\n• Legal requirements and considerations\n• Advertising or communications guidelines\n• Need to align with other suppliers/partners\n• Upcoming opportunities on the horizon\n• Market expansion plans\n• CALD audience considerations\n• Current talent or ambassadors and contracts\n• Previous PR efforts and their outcomes\n• Current media narrative", "Consumer PR": "CONSUMER PR — Key Considerations requirements:\n\nThis section needs to include:\n• Other agencies/teams working on related projects\n• Legal requirements and considerations\n• Advertising or communications guidelines\n• Need to align with other suppliers/partners\n• Upcoming opportunities on the horizon\n• Market expansion plans\n• CALD audience considerations\n• Current talent or ambassadors and contracts\n• Previous PR efforts and their outcomes\n• Current media narrative", "Activations": "ACTIVATIONS — Key Considerations requirements:\n\nThis section needs to include:\n• Anything we need to avoid\n• Insurance requirements\n• Environmental and sustainability considerations (waste management, single-use materials, carbon footprint)\n• Accessibility and inclusivity requirements (wheelchair access, hearing loops, CALD audience considerations)\n• Any concurrent events or activity in the same location that could impact or complement\n• Any key risks identified by the business that we need to be aware of\n• Any key stakeholders, partners, sponsors we need to consider and their requirements"}'),
  ('mandatories', NULL, 'Mandatories', 'Are there any ''must include'' / non-negotiables?', 'Job to be done', NULL, '{"Creative": "CREATIVE — Mandatories requirements:\n\nThis section needs to include:\n• All non-negotiable elements: brand guidelines, logos, colours, typography, legal copy, accessibility requirements, production constraints\n• Must-include elements such as logo lock-ups, disclaimers, proof points\n• Clear separation of what must be included vs what is flexible\n• If there are no mandatories, an explicit statement of ''None'' rather than leaving blank\n• Comprehensive enough to serve as a final compliance checklist", "Design": "DESIGN — Mandatories requirements:\n\nThis section needs to include:\n• Claims, copy, or messages that must be included — with placement specifics (e.g. front of pack vs back of pack)\n• Design mandatories: logo lock-ups, disclaimers, brand colours, typeface\n• Technical specifications (file formats, dimensions, colour profiles)\n• Content inclusions for brand books or design systems if applicable", "Corporate Comms": "CORPORATE COMMS — Mandatories requirements:\n\nThis section needs to include:\n• Mandatory messages, stats, claims, or language that must be included\n• No-go zones: topics, competitors, or comparisons to avoid\n• Legal/regulatory constraints: claims approval, embargo rules, industry regulations\n• Brand guideline parameters: formal vs bold, activist vs neutral, playful vs serious\n• Creative mandatories: logos, spokespeople", "Consumer PR": "CONSUMER PR — Mandatories requirements:\n\nThis section needs to include:\n• Mandatory messages, stats, claims, or language that must be included\n• No-go zones: topics, competitors, or comparisons to avoid\n• Legal/regulatory constraints: claims approval, embargo rules, industry regulations\n• Brand guideline parameters: formal vs bold, activist vs neutral, playful vs serious\n• Creative mandatories: logos, spokespeople\n• Media-specific constraints: embargoes, exclusivity arrangements, approval processes", "Activations": "ACTIVATIONS — Mandatories requirements:\n\nThis section needs to include:\n• Brand guidelines for physical environments — logo placement, colours, materials, finishes\n• Sponsor or partner branding obligations (sizing, placement, co-branding rules)\n• Any mandatory messaging, disclaimers, or legal notices required on-site\n• Product display or sampling compliance (e.g. liquor licensing, food handling, age-gating)\n• Data capture and privacy compliance requirements (opt-in, signage, Privacy Act)\n• Venue-specific mandatories (if a venue has already been selected)\n• Preferred suppliers\n• If no mandatories, explicitly stated as ''None''"}'),
  ('wider-ecosystem', NULL, 'Wider Ecosystem', 'Is there planned or needed paid/owned/earned/partnership/experiential activity?', 'Project Context', NULL, '{"Creative": "CREATIVE — Wider Ecosystem requirements:\n\nThis section needs to include:\n• Other planned activity across paid, owned, earned, shared, or experiential that this work should integrate with\n• Who is delivering each deliverable across the ecosystem\n• Whether this work should align with (consistency) or deliberately differ from (contrast) other activity\n• Any timing clashes with other activity\n• Related campaigns or brand activity happening concurrently", "Design": "DESIGN — Wider Ecosystem requirements:\n\nThis section needs to include:\n• Other design, brand, or campaign work happening that this project should align with\n• Existing design systems or visual identities being developed in parallel\n• Visual consistency requirements across concurrent projects", "Corporate Comms": "CORPORATE COMMS — Wider Ecosystem requirements:\n\nThis section needs to include:\n• What else is happening around this project that we should consider\n• Is anything else going to market at a similar time\n• Risk of conflicting corporate messaging with other activity", "Consumer PR": "CONSUMER PR — Wider Ecosystem requirements:\n\nThis section needs to include:\n• What else is happening around this project that we should consider\n• Is anything else going to market at a similar time\n• Integration opportunities across media, influencer, events, and paid channels", "Activations": "ACTIVATIONS — Wider Ecosystem requirements:\n\nThis section needs to include:\n• How the activation connects to the broader campaign (paid, owned, earned, shared)\n• Whether there is pre-event marketing, social amplification, or post-event content planned\n• Other agencies or teams delivering related elements (creative, media, PR, social, influencer)\n• Whether the activation is a standalone experience or part of a multi-touchpoint campaign\n• Integration with digital/social — live streaming, social walls, hashtag strategy, QR codes"}'),
  ('internal-teams', NULL, 'Internal Teams', 'Are there internal teams delivering part of this project?', 'Project Context', NULL, '{"Creative": "CREATIVE — Internal Teams requirements:\n\nThis section needs to include:\n• Internal teams involved in this project named with their roles\n• Responsibilities and approval authority for each team\n• Key contacts provided\n• Collaboration points and input requirements during creative development\n• Sign-off chain and approval process", "Design": "DESIGN — Internal Teams requirements:\n\nThis section needs to include:\n• Internal teams (marketing, brand, digital, product) involved in the design process\n• Key contacts and their roles in design review and approval\n• Internal brand guardians identified", "Corporate Comms": "CORPORATE COMMS — Internal Teams requirements:\n\nThis section needs to include:\n• Internal stakeholders who must be consulted on corporate messaging\n• Key contacts for alignment\n• Approval and alignment process", "Consumer PR": "CONSUMER PR — Internal Teams requirements:\n\nThis section needs to include:\n• Internal contacts for PR approvals, product information, and brand alignment\n• Key contacts for alignment\n• Sign-off process for media materials and spokesperson quotes", "Activations": "ACTIVATIONS — Internal Teams requirements:\n\nThis section needs to include:\n• Internal teams involved (marketing, brand, sales, trade, operations, legal, procurement)\n• Key contacts and their roles in briefing, review, and on-site decision-making\n• Who has sign-off authority on concept, budget, and on-site changes\n• Whether client staff will be present at the activation and their role (hosting, product knowledge, VIP management)"}'),
  ('external-teams', NULL, 'External Teams', 'Any external partners involved in the project?', 'Project Context', NULL, '{"Creative": "CREATIVE — External Teams requirements:\n\nThis section needs to include:\n• External agencies, vendors, or partners named with their specific scopes\n• How collaboration will work — all-agency lead, or client manages each partner separately\n• Key contacts at each partner organisation\n• Process for sharing assets and information between partners\n• Clear scope delineation to avoid duplication of work", "Design": "DESIGN — External Teams requirements:\n\nThis section needs to include:\n• External partners (print production, digital development, photography, illustration) identified\n• Scope and handover requirements for design assets\n• File format expectations for production partners", "Corporate Comms": "CORPORATE COMMS — External Teams requirements:\n\nThis section needs to include:\n• Relevant external partners (legal counsel, government affairs, investor relations firms)\n• Roles and contact details", "Consumer PR": "CONSUMER PR — External Teams requirements:\n\nThis section needs to include:\n• External partners (media agencies, event production, influencer management, creative agencies)\n• Roles and scope boundaries for each partner", "Activations": "ACTIVATIONS — External Teams requirements:\n\nThis section needs to include:\n• Any preferred suppliers the client would like engaged or used for the project (build partners, AV, brand ambassador agencies, caterers, florists, photographers, venues)\n• Other agencies involved (creative, media, PR, social) and their scope relative to the activation\n• Any sponsorships or partnerships that need to be considered\n• Any external spokespeople you want included e.g. for media interviews"}'),
  ('stakeholder-management', NULL, 'Stakeholder Management', 'Is there likely to be any stakeholder, issue, or risk management needed?', 'Project Context', NULL, '{"Creative": "CREATIVE — Stakeholder Management requirements:\n\nThis section needs to include:\n• Stakeholder sensitivities, reputational risks, or controversial territories that could impact creative choices\n• Tones, topics, or visuals that require caution\n• Potential approval bottlenecks\n• Political landscape the team should understand before starting", "Design": "DESIGN — Stakeholder Management requirements:\n\nThis section needs to include:\n• Stakeholder dynamics that could impact the design process (multiple approvers, conflicting preferences, new leadership with different aesthetic direction)\n• Approval complexity", "Corporate Comms": "CORPORATE COMMS — Stakeholder Management requirements:\n\nThis section needs to include:\n• Foreseeable risks or issues that may arise\n• Potential roadblocks: media sentiment, broader industry context, recent negative coverage, internal changes that may be shared to press, previous negative partner experiences\n• Customer sentiment online: comment sections, emails, customer service enquiries", "Consumer PR": "CONSUMER PR — Stakeholder Management requirements:\n\nThis section needs to include:\n• Foreseeable risks or issues that may arise\n• Potential roadblocks: media sentiment, broader industry context, recent negative coverage, internal changes, previous negative influencer experiences\n• Consumer sentiment online: comment sections, emails, customer service enquiries", "Activations": "ACTIVATIONS — Stakeholder Management Requirements\n\nVIP, sponsor, or partner attendance expected and any specific hosting, branding, or acknowledgement requirements\nWhether media or influencers are being invited and what the ask is (interviews, content capture, photo opportunity)\nAny sensitivities around attendee mix (e.g. competitors, political figures, talent conflicts, community considerations)\nKey stakeholders who need to be consulted or have sign-off on the event experience"}'),
  ('data', NULL, 'Data', 'Do you have relevant data to share or might research be needed?', 'Project Context', NULL, '{"Creative": "CREATIVE — Data requirements:\n\nThis section needs to include:\n• Relevant existing research, data, or insights shared or linked\n• Whether data must be directly referenced in the work or is for inspiration only\n• Whether any additional original research is or might be needed\n• Types of data available (brand tracking, consumer research, sales data, social listening)", "Design": "DESIGN — Data requirements:\n\nThis section needs to include:\n• Relevant data, user research, usability testing, or market research that should inform design\n• Visual references, mood boards, or competitive audits linked\n• Whether data is for reference or must be directly incorporated", "Corporate Comms": "CORPORATE COMMS — Data requirements:\n\nThis section needs to include:\n• Links to owned/external research from brand, product, consumer, audience, or brand lift perspective\n• Data from platforms such as Meltwater, Streem, social listening/scheduling platforms\n• Whether additional research is needed", "Consumer PR": "CONSUMER PR — Data requirements:\n\nThis section needs to include:\n• Links to owned/external research from brand, product, consumer, audience, or brand lift perspective\n• Data from platforms such as Meltwater, Streem, social listening/scheduling platforms\n• Whether additional research is needed", "Activations": "ACTIVATIONS —D ataRequirements\n\nWhat data or insights you want captured from this activation (e.g. leads, email sign-ups, survey responses, product preference, NPS)\nData from previous activations or events that can be shared to inform this one (attendance, feedback, what worked/didn''t)\nAny existing customer or audience data that should shape the activation (CRM segments, loyalty data, purchase behaviour)\nPost-event reporting expectations — what data you need back and in what format"}'),
  ('customer-experience', NULL, 'Customer Experience', 'Any digital/tech pain points related to this project?', 'Project Context', NULL, '{"Creative": "CREATIVE — Customer Experience requirements:\n\nThis section needs to include:\n• Any technical, digital, or platform requirements that affect creative execution\n• Tech stack constraints (website CMS, apps, CRM, social platforms)\n• Known customer experience issues or technical limitations\n• Constraints, dependencies, or opportunities from digital/tech\n• If not applicable, explicitly stated as such", "Design": "DESIGN — Customer Experience requirements:\n\nThis section needs to include:\n• Technical and digital requirements for design work\n• Platform specifications, responsive design requirements, accessibility standards\n• CMS or development environment constraints", "Corporate Comms": "CORPORATE COMMS — Customer Experience requirements:\n\nThis section needs to include:\n• If not typically needed for corporate comms — confirm whether applicable\n• If applicable: website update capabilities, internal comms platforms, customer-facing digital touchpoints", "Consumer PR": "CONSUMER PR — Customer Experience requirements:\n\nThis section needs to include:\n• Digital touchpoints that support PR outcomes (landing pages, social amplification, e-commerce integration)\n• Tracking pixel requirements for media coverage measurement\n• Website capabilities for media-driven traffic", "Activations": "ACTIVATIONS — Customer Experience requirements:\n\nThis section needs to include:\n• The desired attendee journey — from arrival to departure, what should people experience at each stage\n• Any digital or tech integration within the physical experience (AR, VR, interactive screens, apps, social sharing stations, giveaway entry mechanism)\n• Wi-Fi, connectivity, or tech infrastructure requirements\n• Queuing, flow management, and crowd capacity considerations\n• Post-event experience (follow-up comms, content sharing, retargeting)"}'),
  ('channels', NULL, 'Channels', 'Known or likely channels and activity', 'Project Context', NULL, '{"Creative": "CREATIVE — Channels requirements:\n\nThis section needs to include:\n• Specific channels identified across the POES framework (Paid, Owned, Earned, Shared)\n• Primary vs secondary channels prioritised\n• Channel-specific format, tone, or content requirements\n• How channels should influence the creative idea and design approach\n• Integration between channels", "Design": "DESIGN — Channels requirements:\n\nThis section needs to include:\n• Channels and platforms the design work will appear on\n• Specific format requirements, dimensions, and platform-specific design constraints\n• Technical specifications per channel", "Corporate Comms": "CORPORATE COMMS — Channels requirements:\n\nThis section needs to include:\n• Specific channels listed: Print, Broadcast, Digital, Social, Online, LinkedIn, EDM, Substacks, Podcasts, Owned/internal, Testimonials, Paid\n• Channels appropriate to the corporate stakeholder audiences", "Consumer PR": "CONSUMER PR — Channels requirements:\n\nThis section needs to include:\n• Specific channels listed: Print, Broadcast, Digital, Social, Online, LinkedIn, EDM, Substacks, Podcasts, Owned/internal, Testimonials, Paid\n• Earned media targets clearly identified alongside owned and paid amplification", "Activations": "ACTIVATIONS — Channels requirements:\n\nThis section needs to include:\n• The physical channels and touchpoints for the activation (venue, pop-up site, retail location, festival ground, conference floor, public space)\n• Digital and social channels that amplify the activation (social media, live streaming, event apps, email)\n• Pre-event promotion channels (how people find out about and register for the event)\n• On-site content capture and distribution channels\n• Post-event content channels"}'),
  ('budget', NULL, 'Budget', 'Total budget including splits', 'Project Context', NULL, '{"Creative": "CREATIVE — Budget requirements:\n\nThis section needs to include:\n• Total budget figure or range provided\n• What the budget covers vs what requires separate budgets\n• Splits across workstreams if applicable\n• Whether this is full project budget or one phase\n• Whether budget supports high-end production, modular systems, or lightweight execution\n• Budget flexibility or contingency indicated", "Design": "DESIGN — Budget requirements:\n\nThis section needs to include:\n• Budget clearly stated\n• What this budget covers vs next-stage budgets (e.g. design concepts vs artwork vs production)\n• Design-phase budget boundaries", "Corporate Comms": "CORPORATE COMMS — Budget requirements:\n\nThis section needs to include:\n• Total budget for corporate communications program\n• Splits between strategy/retainer/project work\n• Whether media monitoring tools or third-party research costs are included", "Consumer PR": "CONSUMER PR — Budget requirements:\n\nThis section needs to include:\n• Total PR program budget\n• Splits between strategy/retainer/project/events\n• Whether influencer fees, gifting, event production, or media monitoring costs are included", "Activations": "ACTIVATIONS — Budget requirements:\n\nThis section needs to include:\n• Total activation budget or range\n• Budget splits where applicable: concept/design fees, build/fabrication, venue hire, staffing, catering, AV/tech, merchandise/props, logistics/freight, content capture, contingency\n• Whether the budget includes or excludes: venue costs, talent/entertainment fees, travel, accommodation, media amplification\n• Internal merchandise or prop budget identified separately if applicable\n• Whether this is the full activation budget or one phase"}'),
  ('timings', NULL, 'Timings', 'In-market / completion date, other key dates', 'Project Context', NULL, '{"Creative": "CREATIVE — Timings requirements:\n\nThis section needs to include:\n• Critical dates listed (in-market date, launch date, event date)\n• Interim milestones (first presentation, review rounds, final approval)\n• Which dates are immovable vs flexible\n• Dependencies on other workstreams or approvals\n• Production milestones and in-market dates sequenced\n• Whether the timeline is realistic given the scope", "Design": "DESIGN — Timings requirements:\n\nThis section needs to include:\n• Design-specific milestones: concepts, revisions, artwork, production deadlines\n• Print or production lead times that affect the timeline\n• Review/approval milestones", "Corporate Comms": "CORPORATE COMMS — Timings requirements:\n\nThis section needs to include:\n• Strategy presentation, content development milestones, media engagement windows, reporting dates\n• External dependencies: regulatory timelines, board meetings, AGMs", "Consumer PR": "CONSUMER PR — Timings requirements:\n\nThis section needs to include:\n• Campaign launch date, media embargo dates, event dates\n• Influencer activation windows\n• Reporting milestones\n• Media lead times", "Activations": "ACTIVATIONS — Timings requirements:\n\nThis section needs to include:\n• Event date(s) and times — including bump-in and bump-out windows\n• Concept presentation and approval milestones\n• Build, fabrication, and production lead times\n• Venue access dates and any venue-imposed deadlines (plans submission, insurance, permits)\n• Merchandise and props production lead times\n• Staffing briefing and rehearsal dates\n• Any hard deadlines driven by sponsorship commitments, product availability, or public announcements"}'),
  ('location-geography', NULL, 'Location / Geography', 'Where will this run?', 'Project Context', NULL, '{"Creative": "CREATIVE — Location / Geography requirements:\n\nThis section needs to include:\n• Geographic scope clearly stated (country, state/region, city, global)\n• Localisation, translation, or cultural adaptation requirements\n• Market-specific regulatory requirements\n• Whether the work needs to travel across markets or is locally specific\n• NZ-specific cultural factors (Te Reo Māori, Pasifika considerations) if applicable", "Design": "DESIGN — Location / Geography requirements:\n\nThis section needs to include:\n• Geographic scope with design-relevant implications\n• Language requirements, retailer specifications, local regulatory markings\n• Platform or format differences by market", "Corporate Comms": "CORPORATE COMMS — Location / Geography requirements:\n\nThis section needs to include:\n• Geographic scope of the corporate communications program\n• Different stakeholder groups in different markets requiring tailored messaging\n• Regulatory differences by jurisdiction", "Consumer PR": "CONSUMER PR — Location / Geography requirements:\n\nThis section needs to include:\n• Geographic scope of the PR campaign\n• Different media landscapes in different markets\n• Local vs national media targets", "Activations": "ACTIVATIONS — Location / Geography requirements:\n\nThis section needs to include:\n• Specific venue or location (confirmed vs shortlist vs open to recommendation)\n• Venue type: indoor vs outdoor, permanent vs temporary, public vs private\n• Geographic scope — single location, multi-city, touring, national, specific to a region\n• Site-specific logistics: load-in access, parking, power, water, waste"}'),
  ('brand-positioning', NULL, 'Brand Positioning', 'Brand positioning statement or strategy', 'The Brand', NULL, '{"Creative": "CREATIVE — Brand Positioning requirements:\n\nThis section needs to include:\n• Brand positioning statement or clear summary\n• Competitive frame — what category or competitive set the brand positions within\n• Point of difference from competitors\n• Brand strategy documents referenced or attached\n• Whether the positioning is established or being developed", "Design": "DESIGN — Brand Positioning requirements:\n\nThis section needs to include:\n• Brand positioning and how it should be reflected in visual and design choices\n• Existing brand guidelines, mood boards, or visual strategy documents", "Corporate Comms": "CORPORATE COMMS — Brand Positioning requirements:\n\nThis section needs to include:\n• Corporate brand positioning — how the company wants to be perceived by stakeholders, investors, government, and media\n• Corporate narrative documents or ESG positioning statements", "Consumer PR": "CONSUMER PR — Brand Positioning requirements:\n\nThis section needs to include:\n• Brand positioning and how it should be reflected in media-facing communications\n• Key messages or positioning statements pre-approved for media use", "Activations": "ACTIVATIONS — Brand Positioning requirements:\n\nThis section needs to include:\n• Brand positioning and how it should translate into a physical, experiential context\n• The feeling or emotion the activation should evoke that aligns with brand positioning"}'),
  ('key-brand-truth', NULL, 'Key Brand Truth', 'Core brand truth or insight', 'The Brand', NULL, '{"Creative": "CREATIVE — Key Brand Truth requirements:\n\nThis section needs to include:\n• A single, compelling truth about the brand that underpins all communications\n• Why this truth matters to the target audience\n• That the truth is grounded in something real and defensible\n• Brand strategy documents referenced or attached", "Design": "DESIGN — Key Brand Truth requirements:\n\nThis section needs to include:\n• Core brand truth and how it translates into visual identity\n• Visual qualities or design principles that embody this truth", "Corporate Comms": "CORPORATE COMMS — Key Brand Truth requirements:\n\nThis section needs to include:\n• Corporate brand truth — the fundamental reason the company exists and the value it provides to stakeholders and society\n• How this truth manifests in corporate narrative", "Consumer PR": "CONSUMER PR — Key Brand Truth requirements:\n\nThis section needs to include:\n• The brand truth and how it should be reflected in media storytelling\n• What makes this truth newsworthy or culturally relevant", "Activations": "ACTIVATIONS — Key Brand Truth requirements:\n\nThis section needs to include:\n• Core brand truth and how it should come to life in a physical experience\n• The sensory or emotional proof point the activation delivers"}'),
  ('brand-tov-personality', NULL, 'Brand TOV / Personality', 'Brand tone of voice and personality traits', 'The Brand', NULL, '{"Creative": "CREATIVE — Brand TOV / Personality requirements:\n\nThis section needs to include:\n• Brand personality traits listed (e.g. bold, approachable, expert, playful)\n• Tone of voice described with nuance — what the brand sounds like AND doesn''t sound like\n• How tone varies across channels or contexts (e.g. social vs hero film vs retail)\n• TOV guidelines or brand books referenced or attached\n• Enough detail for a writer to produce on-brand copy", "Design": "DESIGN — Brand TOV / Personality requirements:\n\nThis section needs to include:\n• Brand personality translated into visual design choices\n• Visual tone the design should convey (e.g. premium, playful, clinical, bold)\n• Typography, colour, and imagery style preferences reflecting brand personality", "Corporate Comms": "CORPORATE COMMS — Brand TOV / Personality requirements:\n\nThis section needs to include:\n• Corporate tone of voice for stakeholder, media, and investor communications\n• Whether tone differs for internal vs external communications", "Consumer PR": "CONSUMER PR — Brand TOV / Personality requirements:\n\nThis section needs to include:\n• Brand tone of voice for media-facing communications, spokesperson quotes, and social content\n• Tonal adjustments needed for different media tiers (broadsheet vs lifestyle vs social)\n• Spokesperson briefing notes on tone", "Activations": "ACTIVATIONS — Brand TOV / Personality requirements:\n\nThis section needs to include:\n• Brand tone of voice and personality translated to a physical experience — how the brand should ''feel'' in person\n• Staff behaviour and interaction style that reflects brand personality\n• Music, scent, texture, and other sensory cues that embody brand TOV"}'),
  ('key-reasons-to-believe', NULL, 'Key Reasons to Believe', 'Proof points and evidence supporting the brand promise', 'The Brand', NULL, '{"Creative": "CREATIVE — Key Reasons to Believe requirements:\n\nThis section needs to include:\n• Specific, verifiable proof points listed\n• Mix of evidence types (data, awards, testimonials, heritage, innovation, certifications)\n• Which proof points are legally approved claims vs general statements\n• Proof points prioritised by relevance to this brief\n• Brand strategy documents referenced or attached", "Design": "DESIGN — Key Reasons to Believe requirements:\n\nThis section needs to include:\n• Key reasons to believe and how they should be visually represented\n• Certifications, awards, or quality marks that need to appear in design work\n• Usage guidelines for trust marks", "Corporate Comms": "CORPORATE COMMS — Key Reasons to Believe requirements:\n\nThis section needs to include:\n• Corporate reasons to believe: ESG credentials, financial performance, innovation pipeline, leadership credentials, industry awards, stakeholder testimonials\n• Evidence to substantiate each claim", "Consumer PR": "CONSUMER PR — Key Reasons to Believe requirements:\n\nThis section needs to include:\n• Key reasons to believe that media would find compelling\n• Data points, third-party endorsements, awards, customer stories, industry-first claims\n• Evidence that journalists can independently verify", "Activations": "ACTIVATIONS — Key Reasons to Believe requirements:\n\nThis section needs to include:\n• Key reasons to believe that should be demonstrated (not just communicated) through the activation\n• Product proof points that can be experienced first-hand (taste, performance, quality)"}'),
  ('distinctive-brand-assets', NULL, 'Distinctive Brand Assets', 'Recognisable brand elements and assets', 'The Brand', NULL, '{"Creative": "CREATIVE — Distinctive Brand Assets requirements:\n\nThis section needs to include:\n• Distinctive brand assets listed: logo, colours, sonic branding, mascot, tagline, packaging shape, font, patterns\n• Usage rules — which assets are sacred (fixed) vs flexible in application\n• Any Distinctive Asset research and recognition data\n• Brand asset library referenced or accessible", "Design": "DESIGN — Distinctive Brand Assets requirements:\n\nThis section needs to include:\n• Distinctive visual assets with technical specifications (colour codes, file formats, clear space rules)\n• Logo specifications, colour palette, typography, imagery style, iconography, pattern/graphic device libraries", "Corporate Comms": "CORPORATE COMMS — Distinctive Brand Assets requirements:\n\nThis section needs to include:\n• Corporate-specific brand assets distinguished from consumer brand assets\n• Corporate logo, corporate colours, executive headshots, brand marks for sub-brands/divisions", "Consumer PR": "CONSUMER PR — Distinctive Brand Assets requirements:\n\nThis section needs to include:\n• Brand''s distinctive assets for media materials, press kits, and influencer content\n• Approved imagery, logos, product photography, brand visual guidelines for media use\n• Usage guidelines for third-party (media/influencer) use", "Activations": "ACTIVATIONS — Distinctive Brand Assets requirements:\n\nThis section needs to include:\n• Distinctive brand assets and how they should appear in a 3D, physical environment\n• Brand colours, materials, finishes in physical form\n• Sonic branding, scent branding, or other sensory brand assets to incorporate"}'),
  ('brand-guidelines', NULL, 'Brand Guidelines', 'Brand guideline documents and resources', 'The Brand', NULL, '{"Creative": "CREATIVE — Brand Guidelines requirements:\n\nThis section needs to include:\n• Brand guidelines attached, linked, or described\n• Coverage of visual identity, tone of voice, messaging, and application rules\n• Whether guidelines are current and up-to-date\n• Access instructions (link, download, shared drive)\n• Any approved exceptions or upcoming changes noted\n• If guidelines are being developed concurrently, current status stated", "Design": "DESIGN — Brand Guidelines requirements:\n\nThis section needs to include:\n• Brand guidelines with full visual identity system\n• Typography specifications, colour palettes, logo usage rules\n• Photography/illustration style guides\n• Platform-specific design standards\n• Digital and print specifications", "Corporate Comms": "CORPORATE COMMS — Brand Guidelines requirements:\n\nThis section needs to include:\n• Corporate brand guidelines (if different from consumer)\n• Corporate style guides, messaging frameworks\n• Spokesperson guidelines\n• Investor relations communication standards", "Consumer PR": "CONSUMER PR — Brand Guidelines requirements:\n\nThis section needs to include:\n• PR-specific brand guidelines\n• Media kit standards\n• Spokesperson guidelines\n• Social media tone and content guidelines\n• Influencer brief templates or content approval frameworks", "Activations": "ACTIVATIONS — Brand Guidelines requirements:\n\nThis section needs to include:\n• Brand guidelines for physical and experiential environments\n• Build material standards, finish quality expectations\n• Any franchise or co-branding guidelines for shared spaces"}');
